#!/usr/bin/env node
/**
 * ZX Spectrum Copyright Message Display Verification
 * Verifies boot sequence, ROM access, display system, and copyright message rendering
 */
import spec48 from './src/roms/spec48.js';
import { Memory } from './src/memory.mjs';
import { Z80 } from './src/z80.mjs';
import { ULA } from './src/ula.mjs';

console.log('=== ZX Spectrum Copyright Display Verification ===\n');

// --- Setup Emulator Environment ---
const canvas = {
  width: 256,
  height: 192,
  style: {},
  getContext: () => ({
    createImageData: () => ({ data: new Uint8ClampedArray(256 * 192 * 4) }),
    putImageData: () => {},
    imageSmoothingEnabled: false
  })
};
const memory = new Memory(spec48.bytes);
const cpu = new Z80(memory);
const ula = new ULA(memory, canvas);
const ioAdapter = {
  write: (port, value, tstates) => {
    if ((port & 0xFF) === 0xFE) ula.writePort(port, value);
  },
  read: (port) => ((port & 0xFF) === 0xFE ? ula.readPort(port) : 0xFF)
};
cpu.io = ioAdapter;

console.log('- ROM loaded:', spec48.bytes.length, 'bytes');
console.log('- ROM region 0x0000-0x3FFF accessible:', spec48.bytes.length >= 0x4000);
console.log('- Copyright string at 0x153B:',
  spec48.bytes.slice(0x153B, 0x155A).map(b => String.fromCharCode(b)).join('')
);

// --- Boot Sequence Execution ---
cpu.reset();
let instructions = 0;
let foundCopyright = false;
let displayBuffer = [];
const maxInstructions = 8000;
for (; instructions < maxInstructions; instructions++) {
  cpu.step();
  // Check display file for copyright string
  let screenText = '';
  for (let addr = 0x4000; addr < 0x5800; addr++) {
    const val = memory.read(addr);
    if (val >= 32 && val <= 127) screenText += String.fromCharCode(val);
  }
  if (screenText.includes('© 1982 Sinclair Research Ltd')) {
    foundCopyright = true;
    displayBuffer.push(screenText);
    break;
  }
}

// --- Display System Verification ---
const attrBytes = Array.from({length: 0x5AFF - 0x5800 + 1}, (_, i) => memory.read(0x5800 + i));
const displayCleared = Array.from({length: 0x57FF - 0x4000 + 1}, (_, i) => memory.read(0x4000 + i)).every(b => b === 0);
const borderColor = ula.border;

// --- I Register and Interrupts ---
const iRegister = cpu.I;
const frameCounter = ula.frameCount || 0;

// --- System Variables ---
const chans = memory.read(0x5C4B);
const curchl = memory.read(0x5C4D);

// --- Verification Report ---
console.log('\n=== VERIFICATION REPORT ===');
console.log('ROM bytes accessible:', spec48.bytes.length >= 0x4000 ? 'YES' : 'NO');
console.log('Copyright string found at 0x153B:',
  spec48.bytes.slice(0x153B, 0x155A).map(b => String.fromCharCode(b)).join('')
);
console.log('Boot sequence executed:', instructions, 'instructions');
console.log('Display file cleared:', displayCleared ? 'YES' : 'NO');
console.log('Attribute file processed:', attrBytes.length === 0x5AFF - 0x5800 + 1 ? 'YES' : 'NO');
console.log('Border color (ULA):', borderColor, borderColor === 7 ? '(white)' : '(not white)');
console.log('I register after reset:', '0x' + iRegister.toString(16), iRegister === 0x3F ? '(correct)' : '(incorrect)');
console.log('Frame counter:', frameCounter);
console.log('CHANS:', '0x' + chans.toString(16));
console.log('CURCHL:', '0x' + curchl.toString(16));
console.log('Copyright message displayed:', foundCopyright ? 'YES' : 'NO');
if (foundCopyright) {
  console.log('Displayed copyright message:');
  console.log('"© 1982 Sinclair Research Ltd"');
} else {
  console.log('Copyright message NOT found in display file.');
}
console.log('\n=== END OF REPORT ===');

/* eslint-disable no-undef */
/* eslint-env node */
/* global process */
// Playwright config with visual testing support
import { defineConfig } from '@playwright/test';

export default defineConfig({
  testDir: 'tests/e2e',
  use: {
    baseURL: 'http://127.0.0.1:8080',
    trace: 'on-first-retry',
    // Capture screenshots for all tests to enable visual comparisons
    screenshot: 'on',
    actionTimeout: 10000,
  },
  workers: process.env.CI ? '100%' : 1,
  retries: process.env.CI ? 2 : 0,
  projects: [
    { name: 'chromium', use: { browserName: 'chromium' } },
  ],
  reporter: [['list'], ['html']],
  // Configure snapshot directory for approved screenshots
  snapshotDir: './tests/e2e/snapshots',
  expect: {
    toMatchSnapshot: {
      threshold: 0.05,
    },
  },
  // Auto-start dev server before running tests
  webServer: {
    command: 'npm run dev',
    url: 'http://127.0.0.1:8080',
    reuseExistingServer: !process.env.CI,
    timeout: 30000,
  },
});

import playwright from 'playwright';

(async function(){
  const browser = await playwright.chromium.launch({ headless: true });
  const ctx = await browser.newContext();
  const page = await ctx.newPage();
  page.on('console', m => console.log('[PAGE-LOG]', m.type(), m.text()));
  page.on('pageerror', e => console.log('[PAGE-ERROR]', e.message));
  try {
    await page.goto('http://localhost:8080/index.html', { waitUntil: 'load', timeout: 15000 });
    console.log('page loaded');
    // wait for __ZX_DEBUG__ to appear
    for (let i=0;i<60;i++) {
      const dbgExists = await page.evaluate(() => { try { return typeof window.__ZX_DEBUG__ !== 'undefined'; } catch(e) { return false; } });
      if (dbgExists) break;
      await page.waitForTimeout(200);
    }
    // wait for bootComplete up to 30s
    let boot = false;
    for (let i=0;i<120;i++) {
      boot = await page.evaluate(() => { try { return !!(window.__ZX_DEBUG__ && window.__ZX_DEBUG__.bootComplete === true); } catch(e) { return false; } });
      if (boot) break;
      await page.waitForTimeout(250);
    }
    console.log('bootComplete?', boot);
    const autoPatched = await page.evaluate(() => { try { return window.__TEST__ && window.__TEST__.autoPatched ? window.__TEST__.autoPatched.slice(-5) : []; } catch(e){ return String(e); } });
    console.log('autoPatched recent:', autoPatched);
    const lastInjectionCol = await page.evaluate(() => { try { return window.__TEST__ && window.__TEST__._lastInjectionCol; } catch(e) { return null; } });
    console.log('_lastInjectionCol:', lastInjectionCol);
    const hasGlyph = await page.evaluate(() => { try { return (window.__ZX_DEBUG__ && typeof window.__ZX_DEBUG__.hasGlyph7F === 'function') ? window.__ZX_DEBUG__.hasGlyph7F({ topRow: 184 }) : null; } catch(e) { return { error: String(e) }; } });
    console.log('hasGlyph7F:', JSON.stringify(hasGlyph, null, 2));
    await page.screenshot({ path: 'scripts/glyph_check.png' });
  } catch (e) { console.error('script error', e); }
  await ctx.close();
  await browser.close();
})();

/**
 * Keyboard Input Diagnostic Script
 * Run in browser console after emulator is loaded and running.
 * 
 * Usage: Paste this entire script in browser DevTools console
 * or run: import('./scripts/debug-keyboard-input.mjs')
 */

/* eslint-env browser */
/* global window, console, setTimeout */

(function debugKeyboardInput() {
  console.log('=== ZX Spectrum Keyboard Input Diagnostic ===\n');
  
  const emu = window.emulator || window.emu;
  if (!emu) {
    console.error('❌ Emulator not found. Make sure it is running.');
    return;
  }
  
  // 1. Check emulator components
  console.log('1. Component Check:');
  console.log(`   - Emulator: ${emu ? '✅' : '❌'}`);
  console.log(`   - CPU: ${emu.cpu ? '✅' : '❌'}`);
  console.log(`   - Memory: ${emu.memory ? '✅' : '❌'}`);
  console.log(`   - ULA: ${emu.ula ? '✅' : '❌'}`);
  console.log(`   - Input: ${emu.input ? '✅' : '❌'}`);
  console.log(`   - CPU.io adapter: ${emu.cpu && emu.cpu.io ? '✅' : '❌'}`);
  
  // 2. Check ULA keyMatrix state
  console.log('\n2. ULA Key Matrix (should be all 0xFF when no keys pressed):');
  if (emu.ula && emu.ula.keyMatrix) {
    for (let row = 0; row < 8; row++) {
      const val = emu.ula.keyMatrix[row];
      console.log(`   Row ${row}: 0x${val.toString(16).padStart(2, '0')} ${val === 0xff ? '(no keys)' : '⚠️ KEY PRESSED'}`);
    }
  } else {
    console.error('   ❌ ULA keyMatrix not found!');
  }
  
  // 3. Check Input matrix state
  console.log('\n3. Input Matrix:');
  if (emu.input && emu.input.matrix) {
    for (let row = 0; row < 8; row++) {
      const val = emu.input.matrix[row];
      console.log(`   Row ${row}: 0x${val.toString(16).padStart(2, '0')} ${val === 0x1f ? '(no keys)' : '⚠️ KEY PRESSED'}`);
    }
  } else {
    console.error('   ❌ Input matrix not found!');
  }
  
  // 4. Test programmatic key press
  console.log('\n4. Testing programmatic key press (L key):');
  
  // L is in Row 6, bit 1 (mask 0x02) - position 1 in ['enter', 'l', 'k', 'j', 'h']
  const testKey = 'l';
  const expectedRow = 6;
  const expectedMask = 0x02;
  
  // Capture initial state
  const beforeULA = emu.ula?.keyMatrix ? emu.ula.keyMatrix[expectedRow] : null;
  const beforeInput = emu.input?.matrix ? emu.input.matrix[expectedRow] : null;
  
  // Press via Input.pressKey
  if (emu.input && typeof emu.input.pressKey === 'function') {
    const result = emu.input.pressKey(testKey);
    console.log(`   pressKey('${testKey}') returned: ${result}`);
  } else {
    console.error('   ❌ Input.pressKey not available');
    return;
  }
  
  // Apply to ULA
  if (typeof emu._applyInputToULA === 'function') {
    emu._applyInputToULA();
    console.log('   _applyInputToULA() called');
  }
  
  // Check state after press
  const afterInput = emu.input?.matrix ? emu.input.matrix[expectedRow] : null;
  const afterULA = emu.ula?.keyMatrix ? emu.ula.keyMatrix[expectedRow] : null;
  
  console.log(`\n   Input Matrix Row ${expectedRow}:`);
  console.log(`     Before: 0x${beforeInput?.toString(16)} (${beforeInput?.toString(2).padStart(5,'0')})`);
  console.log(`     After:  0x${afterInput?.toString(16)} (${afterInput?.toString(2).padStart(5,'0')})`);
  console.log(`     Expected bit ${1} (mask 0x02) to be cleared`);
  console.log(`     Bit 1 cleared: ${((afterInput & expectedMask) === 0) ? '✅' : '❌'}`);
  
  console.log(`\n   ULA KeyMatrix Row ${expectedRow}:`);
  console.log(`     Before: 0x${beforeULA?.toString(16)}`);
  console.log(`     After:  0x${afterULA?.toString(16)}`);
  console.log(`     Bit 1 cleared: ${((afterULA & expectedMask) === 0) ? '✅' : '❌'}`);
  
  // 5. Test ULA readPort directly
  console.log('\n5. Testing ULA readPort directly:');
  
  // Port 0xBFFE reads Row 6 (A14=0)
  const testPort = 0xBFFE;
  
  if (emu.ula && typeof emu.ula.readPort === 'function') {
    const portResult = emu.ula.readPort(testPort);
    console.log(`   ula.readPort(0x${testPort.toString(16)}) = 0x${portResult.toString(16)}`);
    console.log(`   Binary: ${portResult.toString(2).padStart(8, '0')}`);
    console.log(`   Bit 1 (L key) is ${((portResult & 0x02) === 0) ? '0 (pressed) ✅' : '1 (not pressed) ❌'}`);
    
    // Verify the row selection logic
    const highByte = (testPort >> 8) & 0xff;
    console.log(`\n   Port high byte: 0x${highByte.toString(16)} = ${highByte.toString(2).padStart(8, '0')}`);
    for (let row = 0; row < 8; row++) {
      const selected = ((highByte >> row) & 1) === 0;
      console.log(`     Row ${row} selected: ${selected ? 'YES' : 'no'}`);
    }
  }
  
  // 6. Test CPU IO adapter
  console.log('\n6. Testing CPU IO adapter:');
  if (emu.cpu && emu.cpu.io && typeof emu.cpu.io.read === 'function') {
    const ioResult = emu.cpu.io.read(testPort);
    console.log(`   cpu.io.read(0x${testPort.toString(16)}) = 0x${ioResult.toString(16)}`);
    console.log(`   Bit 1 (L key) is ${((ioResult & 0x02) === 0) ? '0 (pressed) ✅' : '1 (not pressed) ❌'}`);
  } else {
    console.error('   ❌ CPU IO adapter not found!');
  }
  
  // 7. Release the key
  if (emu.input && typeof emu.input.releaseKey === 'function') {
    emu.input.releaseKey(testKey);
    console.log(`\n7. Released '${testKey}' key`);
  }
  
  // 8. Check __TEST__ diagnostics
  console.log('\n8. Test Hook Diagnostics:');
  if (window.__TEST__) {
    console.log(`   keyEvents: ${window.__TEST__.keyEvents?.length || 0} recorded`);
    console.log(`   portReads: ${window.__TEST__.portReads?.length || 0} recorded`);
    console.log(`   lastAppliedKeyMatrix: ${window.__TEST__.lastAppliedKeyMatrix ? 'present' : 'not set'}`);
    
    // Show recent port reads to 0xFE
    const recentFEReads = (window.__TEST__.portReads || [])
      .filter(p => (p.port & 0xff) === 0xfe)
      .slice(-5);
    if (recentFEReads.length > 0) {
      console.log('\n   Recent port 0xFE reads:');
      recentFEReads.forEach(p => {
        console.log(`     port=0x${p.port.toString(16)}, result=0x${p.result.toString(16)}`);
      });
    }
  }
  
  // 9. Summary and recommendations
  console.log('\n=== DIAGNOSIS SUMMARY ===');
  
  const inputOK = afterInput !== null && ((afterInput & expectedMask) === 0);
  const ulaOK = afterULA !== null && ((afterULA & expectedMask) === 0);
  const ioOK = emu.cpu?.io?.read && (emu.cpu.io.read(testPort) & expectedMask) === 0;
  
  if (inputOK && ulaOK && ioOK) {
    console.log('✅ All checks passed - keyboard input chain is working');
    console.log('\nIf typing still does not work, possible causes:');
    console.log('  1. Canvas does not have focus (click on canvas)');
    console.log('  2. ROM is not polling keyboard (check CPU is running)');
    console.log('  3. Interrupts are disabled (ROM keyboard scan happens in interrupt handler)');
    console.log('  4. Key is pressed too briefly for ROM to detect');
  } else {
    if (!inputOK) console.log('❌ Input matrix not updating on key press');
    if (!ulaOK) console.log('❌ ULA keyMatrix not updating (check _applyInputToULA)');
    if (!ioOK) console.log('❌ CPU IO read not returning key state');
  }
  
  // Export for __ZX_DEBUG__
  window.__ZX_DEBUG__ = window.__ZX_DEBUG__ || {};
  window.__ZX_DEBUG__.pressKey = (key) => {
    if (emu.input) {
      emu.input.pressKey(key);
      if (typeof emu._applyInputToULA === 'function') emu._applyInputToULA();
      console.log(`Pressed '${key}' - hold for 100ms then call releaseKey('${key}')`);
    }
  };
  window.__ZX_DEBUG__.releaseKey = (key) => {
    if (emu.input) {
      emu.input.releaseKey(key);
      if (typeof emu._applyInputToULA === 'function') emu._applyInputToULA();
      console.log(`Released '${key}'`);
    }
  };
  window.__ZX_DEBUG__.typeKey = async (key, holdMs = 100) => {
    window.__ZX_DEBUG__.pressKey(key);
    await new Promise(r => setTimeout(r, holdMs));
    window.__ZX_DEBUG__.releaseKey(key);
  };
  
  console.log('\n=== Debug Functions Added to window.__ZX_DEBUG__ ===');
  console.log('  pressKey(key)      - Press a key');
  console.log('  releaseKey(key)    - Release a key');
  console.log('  typeKey(key, ms)   - Press and release after ms delay');
  console.log('\nExample: await __ZX_DEBUG__.typeKey("l", 100)');
})();

(function(){
  if (typeof window === 'undefined') return;
  if (window.__EMU_CAPTURE_INSTALLED) { console.log('[EMU] capture already installed'); return; }
  window.__EMU_CAPTURE_INSTALLED = true;

  window.__EMU_KEY_LOG__ = window.__EMU_KEY_LOG__ || [];

  function shortTarget(t){
    if (!t) return null;
    try{
      return (t.id ? ('#'+t.id) : '') + (t.tagName ? t.tagName.toLowerCase() : (t.nodeName||'')).toLowerCase() + (t.className ? ('.'+(''+t.className).split(/\s+/).join('.')) : '');
    }catch(e){ return String(t); }
  }

  function mk(ev, tag){
    const t = ev.target;
    return {
      ts: Date.now(),
      type: ev.type,
      tag: tag || ev.type,
      target: shortTarget(t),
      targetOuter: (t && t.outerHTML) ? (t.outerHTML.slice(0,300)) : null,
      key: ev.key !== undefined ? ev.key : null,
      code: ev.code !== undefined ? ev.code : null,
      which: ev.which !== undefined ? ev.which : null,
      keyCode: ev.keyCode !== undefined ? ev.keyCode : null,
      isComposing: ev.isComposing === true,
      defaultPrevented: ev.defaultPrevented === true,
      trusted: ev.isTrusted === true,
      bubbles: !!ev.bubbles,
      cancelable: !!ev.cancelable,
      altKey: !!ev.altKey,
      ctrlKey: !!ev.ctrlKey,
      metaKey: !!ev.metaKey,
      shiftKey: !!ev.shiftKey
    };
  }

  function logEvent(ev, label){
    try{
      window.__EMU_KEY_LOG__.push(mk(ev, label));
      if (window.__EMU_KEY_LOG__.length > 32768) window.__EMU_KEY_LOG__.shift();
    }catch(e){ /* ignore */ }
  }

  const evTypes = ['keydown','keypress','keyup','compositionstart','compositionupdate','compositionend','input','focus','blur'];
  evTypes.forEach(ev => {
    window.addEventListener(ev, function(e){ logEvent(e, 'window:'+ev); }, true);
    document.addEventListener(ev, function(e){ logEvent(e, 'document:'+ev); }, true);
  });

  const canvas = document.getElementById && document.getElementById('screen');
  if (canvas){ ['keydown','keypress','keyup','focus','blur','input'].forEach(ev => canvas.addEventListener(ev, function(e){ logEvent(e, 'canvas:'+ev); }, true)); }

  // helper to record focus/overlay state snapshot
  window.__EMU_INSPECT__ = function(){
    try{
      const out = {};
      out.time = Date.now();
      out.activeElement = document.activeElement ? (document.activeElement.id || document.activeElement.tagName || document.activeElement.nodeName) : null;
      out.activeElementOuter = document.activeElement && document.activeElement.outerHTML ? document.activeElement.outerHTML.slice(0,200) : null;
      out.hiddenInput = !!document.getElementById('__emu_hidden_input');
      out.hiddenInputFocused = document.getElementById('__emu_hidden_input') ? (document.activeElement === document.getElementById('__emu_hidden_input')) : false;
      const screen = document.getElementById('screen');
      out.screen = screen ? { id: screen.id || null, tabIndex: screen.getAttribute && screen.getAttribute('tabindex'), rect: screen.getBoundingClientRect ? screen.getBoundingClientRect().toJSON() : null } : null;
      if (screen){ const r = screen.getBoundingClientRect(); const el = document.elementFromPoint(r.left + r.width/2, r.top + r.height/2); out.elementAtCanvasCenter = el ? (el.id || el.tagName || (el.outerHTML && el.outerHTML.slice(0,200))) : null; }
      try { out.windowTest = window.__TEST__ ? { inputListeners: window.__TEST__.inputListeners || null, keyEventsTail: (window.__TEST__.keyEvents || []).slice(-20) } : null; } catch { /* ignore */ }
      console.log(out);
      return out;
    }catch(e){ console.error('[EMU] inspect failed', e); return null; }
  };

  window.__EMU_DUMP_LOG__ = function(filename){
    try{
      const payload = {
        meta: {
          createdAt: Date.now(),
          userAgent: navigator.userAgent,
          url: location.href
        },
        events: window.__EMU_KEY_LOG__ || []
      };
      const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename || ('emu-key-log-' + (new Date()).toISOString().replace(/[:.]/g,'-') + '.json');
      document.body.appendChild(a);
      a.click();
      setTimeout(function(){ try{ URL.revokeObjectURL(url); a.remove(); } catch { /* ignore */ } }, 1000);
      console.log('[EMU] dumped', a.download, 'events:', payload.events.length);
      return payload;
    }catch(e){ console.error('[EMU] dump failed', e); return null; }
  };

  window.__EMU_CLEAR_LOG__ = function(){ window.__EMU_KEY_LOG__ = []; console.log('[EMU] log cleared'); };

  // keyboard shortcut: Ctrl+Shift+S to dump
  window.addEventListener('keydown', function(e){ try{ if (e.ctrlKey && e.shiftKey && (e.key === 'S' || e.key === 's')){ e.preventDefault(); window.__EMU_DUMP_LOG__(); } }catch{ /* ignore */ } }, true);

  // add a small dump button (non-invasive)
  try{
    const btn = document.createElement('button');
    btn.id = '__emu_dump_button';
    btn.textContent = 'Dump EMU Log';
    btn.style.cssText = 'position:fixed;right:8px;bottom:8px;z-index:2147483647;padding:6px 8px;font-size:11px;opacity:0.85;';
    btn.addEventListener('click', function(){ window.__EMU_DUMP_LOG__(); });
    document.body.appendChild(btn);
  } catch { /* ignore */ }

  console.log('[EMU] capture installed. Use window.__EMU_DUMP_LOG__() to save a JSON log, window.__EMU_INSPECT__() to inspect focus/state, and window.__EMU_CLEAR_LOG__() to clear. Shortcut Ctrl+Shift+S available.');
})();

#!/usr/bin/env node
/* eslint-disable no-console */
/**
 * Diagnose Jetpac warm-up by loading the snapshot in the same way applySnapshot
 * does and comparing the post-warm-up CPU state + memWrites with the jsspeccy3
 * reference trace.
 *
 * Usage: node scripts/diagnose_jetpac_warmup.mjs
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath, pathToFileURL } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');

// Shim browser globals for main.mjs
if (typeof globalThis.window === 'undefined') {
  globalThis.window = { addEventListener: () => {}, dispatchEvent: () => {} };
}
if (typeof globalThis.document === 'undefined') {
  globalThis.document = { getElementById: () => null };
}

// Enable warm-up logging
globalThis.__ZX_WARMUP_LOG = true;

const { Emulator } = await import(pathToFileURL(path.join(ROOT, 'src', 'main.mjs')).href);
const { Loader } = await import(pathToFileURL(path.join(ROOT, 'src', 'loader.mjs')).href);

// Stub canvas
const canvasStub = {
  width: 320, height: 240, style: {},
  getContext: () => ({
    createImageData: () => ({ data: new Uint8ClampedArray(320 * 240 * 4) }),
    putImageData: () => {}, fillRect: () => {}, imageSmoothingEnabled: false
  }),
  toDataURL: () => ''
};

const emu = new Emulator({ canvas: canvasStub, statusEl: {} });

// Load the REAL ROM so IM1 ISR at 0x0038 works correctly
const romPath = path.join(ROOT, 'roms', 'spec48.rom');
let romBuffer = null;
if (fs.existsSync(romPath)) {
  const romData = fs.readFileSync(romPath);
  romBuffer = romData.buffer.slice(romData.byteOffset, romData.byteOffset + romData.byteLength);
  console.log('Loaded real ROM:', romPath, '(' + romData.length + ' bytes)');
} else {
  console.log('WARNING: No ROM found at', romPath, '— using 0xFF fill (IM1 ISR will cascade)');
}
await emu._createCore(romBuffer);

// Load the .z80 file
const z80Path = path.join(ROOT, 'traces', 'jetpac.z80');
const z80Buf = fs.readFileSync(z80Path);
const parsed = Loader.parseZ80(z80Buf.buffer);

console.log('=== SNAPSHOT REGISTERS ===');
const r = parsed.snapshot.registers;
console.log({
  PC: r.PC, SP: r.SP, IFF1: r.IFF1, IFF2: r.IFF2, IM: r.IM,
  I: r.I, R: r.R, A: r.A, F: r.F,
  B: r.B, C: r.C, D: r.D, E: r.E, H: r.H, L: r.L
});
console.log('tstates:', parsed.snapshot.tstates);
console.log();

// Intercept memWrites during warm-up
const memWrites = [];
