function disassembleAt(readByte, addr, count=40){
  let pc = addr;
  for(let i=0;i<count && pc<0xffff;i++){
    const op = readByte(pc) & 0xff;
    let instr = '???';
    let len = 1;
    if (op === 0xCD) { const nn = readByte(pc+1) | (readByte(pc+2)<<8); instr = `CALL ${hex(nn)}`; len=3; }
    else if (op === 0xDB) { instr = `IN A,(0x${hex(readByte(pc+1),2)})`; len=2; }
    else if (op === 0xED && (readByte(pc+1) === 0x78)) { instr = 'IN A,(C)'; len=2; }
    else if (op === 0x10) { const off=readByte(pc+1); const signed = (off&0x80)?off-0x100:off; instr = `DJNZ ${hex((pc+2+signed)&0xffff)}`; len=2; }
    else if (op === 0xCB) { const sub = readByte(pc+1); const regNames = ['B','C','D','E','H','L','(HL)','A']; const reg = regNames[sub & 7]; const bit = (sub>>3)&7; if (sub>=0x40 && sub<0x80) instr = `BIT ${bit},${reg}`; else instr = `CB ${hex(sub,2)}`; len=2; }
    else if (op === 0x23) instr = 'INC HL';
    else if (op === 0x1A) instr = 'LD A,(DE)';
    else if (op === 0x77) instr = 'LD (HL),A';
    else if (op === 0x13) instr = 'INC DE';
    else if (op === 0x24) instr = 'INC H';
    else if (op === 0xD1) instr = 'POP DE';
    else if (op === 0xC1) instr = 'POP BC';
    else if (op === 0x7C) instr = 'LD A,H';
    else if (op === 0xD6) { instr = `SUB ${hex(readByte(pc+1),2)}`; len=2; }
    else if (op === 0x20) { const off = readByte(pc+1); const signed = (off&0x80)?off-0x100:off; instr = `JR NZ,${hex((pc+2+signed)&0xffff)}`; len=2; }
    else if (op === 0x18) { const off = readByte(pc+1); const signed = (off&0x80)?off-0x100:off; instr = `JR ${hex((pc+2+signed)&0xffff)}`; len=2; }
    else if (op === 0xCB) { instr = `CB ${hex(readByte(pc+1),2)}`; len =2; }
    else {
      instr = `OP 0x${hex(op,2)}`;
    }
    const bytes = Array.from({length:len}, (_,k)=>hex(readByte(pc+k),2)).join(' ');
    console.log(`${hex(pc)}: ${bytes.padEnd(12)} ${instr}`);
    pc += len;
  }
}

