/**
 * Micro-trace: run Jetpac from PC=29026 and log the first N instructions
 * to find where our execution diverges from jsspeccy3 reference.
 * 
 * Also disassembles the main game loop around PC=29022-29030.
 */
import { Loader } from '../src/loader.mjs';
import { Emulator } from '../src/main.mjs';
import { Memory } from '../src/memory.mjs';
import { Z80 } from '../src/z80.mjs';
import fs from 'fs';
import { pathToFileURL } from 'url';

const hex8 = n => n.toString(16).padStart(2, '0');
const hex16 = n => n.toString(16).padStart(4, '0');

// Minimal Z80 disassembler (just enough for tracing)
function disasmOne(mem, pc) {
  const op = mem.read(pc);
  const op1 = mem.read((pc + 1) & 0xffff);
  const op2 = mem.read((pc + 2) & 0xffff);
  const nn = op1 | (op2 << 8);

  // Common single-byte
  const simpleOps = {
    0x00: ['NOP', 1], 0x76: ['HALT', 1], 0xFB: ['EI', 1], 0xF3: ['DI', 1],
    0xC9: ['RET', 1], 0xAF: ['XOR A', 1], 0xA7: ['AND A', 1], 0xB7: ['OR A', 1],
    0xB0: ['OR B', 1], 0xB1: ['OR C', 1], 0xB2: ['OR D', 1], 0xB3: ['OR E', 1],
    0xB4: ['OR H', 1], 0xB5: ['OR L', 1],
    0xFE: [`CP 0x${hex8(op1)}`, 2],
    0xE6: [`AND 0x${hex8(op1)}`, 2],
    0xF6: [`OR 0x${hex8(op1)}`, 2],
    0xD6: [`SUB 0x${hex8(op1)}`, 2],
    0xC6: [`ADD A,0x${hex8(op1)}`, 2],
    0xEE: [`XOR 0x${hex8(op1)}`, 2],
    0x3E: [`LD A,0x${hex8(op1)}`, 2],
    0x06: [`LD B,0x${hex8(op1)}`, 2],
    0x0E: [`LD C,0x${hex8(op1)}`, 2],
    0x16: [`LD D,0x${hex8(op1)}`, 2],
    0x1E: [`LD E,0x${hex8(op1)}`, 2],
    0x26: [`LD H,0x${hex8(op1)}`, 2],
    0x2E: [`LD L,0x${hex8(op1)}`, 2],
  };
  if (simpleOps[op]) return simpleOps[op];

  // LD r,r (0x40-0x7F except 0x76)
  const regs8 = ['B', 'C', 'D', 'E', 'H', 'L', '(HL)', 'A'];
  if (op >= 0x40 && op <= 0x7F) {
    const dst = regs8[(op >> 3) & 7];
    const src = regs8[op & 7];
    return [`LD ${dst},${src}`, 1];
  }

  // ALU r
  const aluOps = ['ADD A,', 'ADC A,', 'SUB ', 'SBC A,', 'AND ', 'XOR ', 'OR ', 'CP '];
  if (op >= 0x80 && op <= 0xBF) {
    const alu = aluOps[(op >> 3) & 7];
    const src = regs8[op & 7];
    return [`${alu}${src}`, 1];
  }

  // 16-bit loads and ops
  const regs16 = ['BC', 'DE', 'HL', 'SP'];
  const regs16push = ['BC', 'DE', 'HL', 'AF'];
  if ((op & 0xCF) === 0x01) return [`LD ${regs16[(op >> 4) & 3]},0x${hex16(nn)}`, 3];
  if ((op & 0xCF) === 0x09) return [`ADD HL,${regs16[(op >> 4) & 3]}`, 1];
  if ((op & 0xCF) === 0x03) return [`INC ${regs16[(op >> 4) & 3]}`, 1];
  if ((op & 0xCF) === 0x0B) return [`DEC ${regs16[(op >> 4) & 3]}`, 1];
  if ((op & 0xC7) === 0x04) return [`INC ${regs8[(op >> 3) & 7]}`, 1];
  if ((op & 0xC7) === 0x05) return [`DEC ${regs8[(op >> 3) & 7]}`, 1];

  // Stack
  if ((op & 0xCF) === 0xC5) return [`PUSH ${regs16push[(op >> 4) & 3]}`, 1];
  if ((op & 0xCF) === 0xC1) return [`POP ${regs16push[(op >> 4) & 3]}`, 1];

  // Jumps/Calls
  const conds = ['NZ', 'Z', 'NC', 'C', 'PO', 'PE', 'P', 'M'];
  if (op === 0xC3) return [`JP 0x${hex16(nn)}`, 3];
  if (op === 0xCD) return [`CALL 0x${hex16(nn)}`, 3];
  if (op === 0x18) return [`JR ${(op1 > 127 ? op1 - 256 : op1) + 2}  (-> 0x${hex16((pc + 2 + (op1 > 127 ? op1 - 256 : op1)) & 0xffff)})`, 2];
  if (op === 0x20) return [`JR NZ,${(op1 > 127 ? op1 - 256 : op1) + 2}  (-> 0x${hex16((pc + 2 + (op1 > 127 ? op1 - 256 : op1)) & 0xffff)})`, 2];
  if (op === 0x28) return [`JR Z,${(op1 > 127 ? op1 - 256 : op1) + 2}  (-> 0x${hex16((pc + 2 + (op1 > 127 ? op1 - 256 : op1)) & 0xffff)})`, 2];
  if (op === 0x38) return [`JR C,${(op1 > 127 ? op1 - 256 : op1) + 2}  (-> 0x${hex16((pc + 2 + (op1 > 127 ? op1 - 256 : op1)) & 0xffff)})`, 2];
  if (op === 0x30) return [`JR NC,${(op1 > 127 ? op1 - 256 : op1) + 2}  (-> 0x${hex16((pc + 2 + (op1 > 127 ? op1 - 256 : op1)) & 0xffff)})`, 2];
  if ((op & 0xC7) === 0xC2) return [`JP ${conds[(op >> 3) & 7]},0x${hex16(nn)}`, 3];
  if ((op & 0xC7) === 0xC4) return [`CALL ${conds[(op >> 3) & 7]},0x${hex16(nn)}`, 3];
  if ((op & 0xC7) === 0xC0) return [`RET ${conds[(op >> 3) & 7]}`, 1];
  if (op === 0xE9) return ['JP (HL)', 1];
  if (op === 0x10) return [`DJNZ ${(op1 > 127 ? op1 - 256 : op1) + 2}  (-> 0x${hex16((pc + 2 + (op1 > 127 ? op1 - 256 : op1)) & 0xffff)})`, 2];

  // I/O
  if (op === 0xDB) return [`IN A,(0x${hex8(op1)})`, 2];
  if (op === 0xD3) return [`OUT (0x${hex8(op1)}),A`, 2];

  // RST
  if ((op & 0xC7) === 0xC7) return [`RST 0x${hex8(op & 0x38)}`, 1];

  // LD indirect
  if (op === 0x32) return [`LD (0x${hex16(nn)}),A`, 3];
  if (op === 0x3A) return [`LD A,(0x${hex16(nn)})`, 3];
  if (op === 0x22) return [`LD (0x${hex16(nn)}),HL`, 3];
  if (op === 0x2A) return [`LD HL,(0x${hex16(nn)})`, 3];
  if (op === 0x36) return [`LD (HL),0x${hex8(op1)}`, 2];
  if (op === 0x0A) return ['LD A,(BC)', 1];
  if (op === 0x1A) return ['LD A,(DE)', 1];
  if (op === 0x02) return ['LD (BC),A', 1];
  if (op === 0x12) return ['LD (DE),A', 1];

  // Rotate/shift
  if (op === 0x07) return ['RLCA', 1];
  if (op === 0x0F) return ['RRCA', 1];
  if (op === 0x17) return ['RLA', 1];
  if (op === 0x1F) return ['RRA', 1];

  // EX
  if (op === 0xEB) return ['EX DE,HL', 1];
  if (op === 0xD9) return ['EXX', 1];
  if (op === 0x08) return ['EX AF,AF\'', 1];
  if (op === 0xE3) return ['EX (SP),HL', 1];

  // CB prefix
  if (op === 0xCB) {
    const bitOps = ['RLC', 'RRC', 'RL', 'RR', 'SLA', 'SRA', 'SLL', 'SRL'];
    if (op1 < 0x40) return [`${bitOps[(op1 >> 3) & 7]} ${regs8[op1 & 7]}`, 2];
    if (op1 < 0x80) return [`BIT ${(op1 >> 3) & 7},${regs8[op1 & 7]}`, 2];
    if (op1 < 0xC0) return [`RES ${(op1 >> 3) & 7},${regs8[op1 & 7]}`, 2];
    return [`SET ${(op1 >> 3) & 7},${regs8[op1 & 7]}`, 2];
  }

  // ED prefix
  if (op === 0xED) {
    if (op1 === 0x78) return ['IN A,(C)', 2];
    if (op1 === 0x40) return ['IN B,(C)', 2];
    if (op1 === 0x48) return ['IN C,(C)', 2];
    if (op1 === 0x50) return ['IN D,(C)', 2];
    if (op1 === 0x58) return ['IN E,(C)', 2];
    if (op1 === 0x60) return ['IN H,(C)', 2];
    if (op1 === 0x68) return ['IN L,(C)', 2];
    if (op1 === 0x79) return ['OUT (C),A', 2];
    if (op1 === 0x41) return ['OUT (C),B', 2];
    if (op1 === 0x49) return ['OUT (C),C', 2];
    if (op1 === 0x51) return ['OUT (C),D', 2];
    if (op1 === 0x59) return ['OUT (C),E', 2];
    if (op1 === 0xB0) return ['LDIR', 2];
    if (op1 === 0xB8) return ['LDDR', 2];
    if (op1 === 0xA0) return ['LDI', 2];
    if (op1 === 0xA8) return ['LDD', 2];
    if (op1 === 0xB1) return ['CPIR', 2];
    if (op1 === 0xB9) return ['CPDR', 2];
    if (op1 === 0x56) return ['IM 1', 2];
    if (op1 === 0x46) return ['IM 0', 2];
    if (op1 === 0x5E) return ['IM 2', 2];
    if (op1 === 0x4D) return ['RETI', 2];
    if (op1 === 0x45) return ['RETN', 2];
    if (op1 === 0x47) return ['LD I,A', 2];
    if (op1 === 0x4F) return ['LD R,A', 2];
    if (op1 === 0x57) return ['LD A,I', 2];
    if (op1 === 0x5F) return ['LD A,R', 2];
    if ((op1 & 0xCF) === 0x42) return [`SBC HL,${regs16[(op1 >> 4) & 3]}`, 2];
    if ((op1 & 0xCF) === 0x4A) return [`ADC HL,${regs16[(op1 >> 4) & 3]}`, 2];
    if ((op1 & 0xCF) === 0x43) return [`LD (0x${hex16(op2 | (mem.read((pc + 3) & 0xffff) << 8))}),${regs16[(op1 >> 4) & 3]}`, 4];
    if ((op1 & 0xCF) === 0x4B) return [`LD ${regs16[(op1 >> 4) & 3]},(0x${hex16(op2 | (mem.read((pc + 3) & 0xffff) << 8))})`, 4];
    return [`ED ${hex8(op1)}`, 2];
  }

  // DD / FD prefix (IX/IY)
  if (op === 0xDD || op === 0xFD) {
    const r = op === 0xDD ? 'IX' : 'IY';
    if (op1 === 0x21) return [`LD ${r},0x${hex16(op2 | (mem.read((pc + 3) & 0xffff) << 8))}`, 4];
    if (op1 === 0xE5) return [`PUSH ${r}`, 2];
    if (op1 === 0xE1) return [`POP ${r}`, 2];
    if (op1 === 0x36) { const d = op2; const n = mem.read((pc + 3) & 0xffff); return [`LD (${r}+${d}),0x${hex8(n)}`, 4]; }
    if (op1 === 0x23) return [`INC ${r}`, 2];
    if (op1 === 0x2B) return [`DEC ${r}`, 2];
    if (op1 === 0xE9) return [`JP (${r})`, 2];
    // LD r,(IX+d) / LD (IX+d),r
    if ((op1 & 0xC7) === 0x46) return [`LD ${regs8[(op1 >> 3) & 7]},(${r}+${op2})`, 3];
    if ((op1 & 0xF8) === 0x70) return [`LD (${r}+${op2}),${regs8[op1 & 7]}`, 3];
    return [`${r} prefix: ${hex8(op1)} ${hex8(op2)}`, 2];
  }

  return [`DB 0x${hex8(op)}`, 1];
}

