    }

    if (ext === 'z80') {
      return this.parseZ80(arrayBuffer);
    }

    if (ext === 'sna') {
      return this.parseSNA(arrayBuffer);
    }

    // Unknown format: return raw
    return { type: 'unknown', raw: arrayBuffer };
  }
