        if (bootProgress.complete || currentPC === 0x11CB || currentPC > 0x100) {
          bootComplete = true;
          finalPC = currentPC;
          break;
        }

        if (currentPC === 0x15C4) {
          console.log('✓ Reached copyright display routine at 0x15C4');
        }
      }

      const memoryCheck = await page.evaluate(() => {
        if (window.__ZX_DEBUG__ && window.__ZX_DEBUG__.readROM) {
          const addr = 0x153B;
          let text = '';
          for (let i = 0; i < 50; i++) {
