        const emu = window.emulator || window.emu;
        out.frameBufferNonZero = false;
        if (emu && emu.ula && emu.ula.frameBuffer && emu.ula.frameBuffer.buffer) {
          const buf = emu.ula.frameBuffer.buffer;
