async function waitForStartSequence(page, { baselinePixels = null, baselineMem = null, baselineDisplay = null, timeouts = { rocket: 3000, beep: 3500, enemy: 8000 } } = {}) {
  const result = { rocket: false, beep: false, enemy: false, timings: {} };

