    const out = [];
    for (const c of clusters) {
      const col = Math.floor((c.x - 32) / 8);
      const topRow = Math.floor(c.y / 8) * 8;
      if (col >= 0 && col < 32) out.push({ topRow, cols: [col] });
    }
    return out;
  });
}

