          if (wantsRocketWrites && refF0 && refF0.regs && typeof refF0.regs.PC === 'number') {
            const refPC = refF0.regs.PC & 0xffff;
            const ramOffset = refPC - 0x4000;

            // If the parsed snapshot does not contain the loop at the
            // reference PC, do NOT silently patch RAM. Instead, recommend
            // regenerating the canonical parsed snapshot or explicitly
            // opt-in to synthetic injection for diagnostics.
            const hasLoopAtRef = (ramOffset >= 0 && ramOffset + 16 <= (ram.length || 0xC000) && Array.from(ram.slice(ramOffset, ramOffset + 16)).some(b => b !== 0x00));
            if (!hasLoopAtRef) {
              console.warn('[TraceDiag] reference expects rocket writes but parsed snapshot does not contain the ROM loop at 0x' + refPC.toString(16) + '.');
              console.warn('[TraceDiag] To reproduce reference behavior temporarily, set ALLOW_SYNTHETIC_INJECTION=1 (not recommended for CI).');

              // If explicitly allowed, perform the legacy synthetic injection
              if (process.env.ALLOW_SYNTHETIC_INJECTION === '1' && !FORCE_SYNTHETIC) {
                const loopCode = new Uint8Array([0x21,0x00,0x40, 0x3E,0xAA, 0x06,0x10, 0x77,0x23,0xD3,0xFE, 0x10,0xFA, 0xC3,0x03,0x80]);
                if (ramOffset >= 0 && ramOffset + loopCode.length <= (ram.length || 0xC000)) {
                  for (let i = 0; i < loopCode.length; i++) {
                    ram[ramOffset + i] = loopCode[i] & 0xff;
                    const pageIndex = 1 + Math.floor((ramOffset + i) / 0x4000);
                    const pageOff = (ramOffset + i) % 0x4000;
                    if (emu.memory.pages[pageIndex]) emu.memory.pages[pageIndex][pageOff] = loopCode[i] & 0xff;
                  }
                  console.log('[TraceDiag] (opt-in) injected synthetic loop at 0x' + refPC.toString(16));
                }
              }
            }
          }
        }
      } catch (e) { /* non-fatal; continue with loaded RAM */ }
    }

    // Create CPU if missing
    if (!emu.cpu) emu.cpu = new Z80(emu.memory);
    emu.cpu.attachMemory = emu.memory; // (noop, exists for clarity)

    // Set registers
    const regs = parsed.snapshot.registers || {};

    // Historically we seeded the CPU registers from the external
    // jsspeccy reference before starting the capture.  That was done to
    // compensate for the fact that the canonical trace file begins *after*
    // a single warm-up frame, while the raw snapshot contains the state
    // immediately at save-time.  Rather than force the emulator into a
    // different initial state, we now simply execute the warm frame here
    // so our first recorded frame aligns with the reference.
    //
    // The seeding code is left commented for reference but is disabled by
    // default – it should only be used when reproducing older behaviour or
    // when FORCE_SYNTHETIC is explicitly requested.
    // const REF_TRACE_PATH = path.resolve(process.cwd(), 'traces', 'jsspeccy_reference_jetpac_trace.json');
    // console.log('[TraceDiag] seed-check FORCE_SYNTHETIC=', FORCE_SYNTHETIC, 'REF_EXISTS=', fs.existsSync(REF_TRACE_PATH));
    // if (!FORCE_SYNTHETIC && fs.existsSync(REF_TRACE_PATH)) {
    //   try {
    //     const ref = JSON.parse(fs.readFileSync(REF_TRACE_PATH, 'utf8'));
    //     if (ref && Array.isArray(ref.frames) && ref.frames.length > 0 && ref.frames[0].regs) {
    //       console.log('[TraceDiag] seeding CPU registers from jsspeccy_reference_jetpac_trace.json (frame-0)');
    //       Object.assign(regs, ref.frames[0].regs);
    //     }
    //   } catch (e) { console.log('[TraceDiag] seed-check parse error', e && e.message); /* ignore parse errors and continue with parsed snapshot */ }
    // }

    const cpu = emu.cpu;
    console.log('[TraceDiag] applying regs -> PC:', regs.PC, 'R:', regs.R, 'IFF1:', regs.IFF1, 'IFF2:', regs.IFF2);
    if (typeof regs.PC === 'number') cpu.PC = regs.PC & 0xffff;
    if (typeof regs.SP === 'number') cpu.SP = regs.SP & 0xffff;
    if (typeof regs.A === 'number') cpu.A = regs.A & 0xff;
    if (typeof regs.F === 'number') cpu.F = regs.F & 0xff;
    if (typeof regs.B === 'number') cpu.B = regs.B & 0xff;
    if (typeof regs.C === 'number') cpu.C = regs.C & 0xff;
    if (typeof regs.D === 'number') cpu.D = regs.D & 0xff;
    if (typeof regs.E === 'number') cpu.E = regs.E & 0xff;
    if (typeof regs.H === 'number') cpu.H = regs.H & 0xff;
    if (typeof regs.L === 'number') cpu.L = regs.L & 0xff;
    if (typeof regs.IX === 'number') cpu.IX = regs.IX & 0xffff;
    if (typeof regs.IY === 'number') cpu.IY = regs.IY & 0xffff;
    if (typeof regs.I === 'number') cpu.I = regs.I & 0xff;
    if (typeof regs.R === 'number') cpu.R = regs.R & 0xff;
    if (typeof regs.IFF1 !== 'undefined') cpu.IFF1 = !!regs.IFF1;
    if (typeof regs.IFF2 !== 'undefined') cpu.IFF2 = !!regs.IFF2;
    if (typeof regs.IM === 'number') cpu.IM = regs.IM & 0xff;

    // Alternate registers
    if (typeof regs.A2 === 'number') cpu.A_ = regs.A2 & 0xff;
    if (typeof regs.F2 === 'number') cpu.F_ = regs.F2 & 0xff;
    if (typeof regs.B2 === 'number') cpu.B_ = regs.B2 & 0xff;
    if (typeof regs.C2 === 'number') cpu.C_ = regs.C2 & 0xff;

    // The legacy "force PC" block is no longer required now that we
    // execute a warm-up frame above.  Leave it in place commented out in
    // case someone wants to reproduce the previous behaviour or debug
    // mismatched snapshots.
    // try {
    //   const REF_TRACE_PATH = path.resolve(process.cwd(), 'traces', 'jsspeccy_reference_jetpac_trace.json');
    //   if (!FORCE_SYNTHETIC && fs.existsSync(REF_TRACE_PATH)) {
    //     const ref = JSON.parse(fs.readFileSync(REF_TRACE_PATH, 'utf8'));
    //     if (ref && Array.isArray(ref.frames) && ref.frames.length > 0 && ref.frames[0].regs && typeof ref.frames[0].regs.PC === 'number') {
    //       cpu.PC = ref.frames[0].regs.PC & 0xffff;
    //       console.log('[TraceDiag] forced cpu.PC to reference value 0x' + cpu.PC.toString(16));
    //     }
    //   }
    // } catch (e) { /* non-fatal */ }
    if (typeof regs.D2 === 'number') cpu.D_ = regs.D2 & 0xff;
    if (typeof regs.E2 === 'number') cpu.E_ = regs.E2 & 0xff;
    if (typeof regs.H2 === 'number') cpu.H_ = regs.H2 & 0xff;
    if (typeof regs.L2 === 'number') cpu.L_ = regs.L2 & 0xff;

    // Restore border if present
    if (typeof regs.borderColor === 'number' && emu.ula) { emu.ula.border = regs.borderColor & 0x07; if (typeof emu.ula._updateCanvasBorder === 'function') emu.ula._updateCanvasBorder(); }

  } catch (err) {
    console.error('Manual applySnapshot failed:', err);
    throw new Error('Failed to apply Jetpac snapshot');
  }

  // Prepare CPU/memory for tracing
  const cpu = emu.cpu;
  const mem = emu.memory;
  const sound = emu.sound;

  // Clear any prior logs
  emu._portWrites = [];
  emu._executedOpcodes = [];

  // Enable memory watch so we capture writes to 0x4000..0x5AFF in mem._memWrites
  // Also turn on debug mode so the watch callback records events
  emu._debugEnabled = true;
  if (typeof emu._enableMemoryWatch === 'function') emu._enableMemoryWatch();

  // Diagnostic: write once to video RAM to confirm mem watch works
  try {
    const res = mem.write(0x4000, 0xAA);
    console.log('[TraceDiag] manual mem.write returned:', res);
    console.log('[TraceDiag] mem.pages[1][0]=', mem.pages[1] ? mem.pages[1][0] : undefined);
    console.log('[TraceDiag] mem._memWrites length =', (mem._memWrites || []).length);
    if (mem._memWrites && mem._memWrites.length > 0) console.log('[TraceDiag] first mem write evt:', mem._memWrites[0]);
  } catch (e) { console.log('[TraceDiag] manual mem.write failed:', e); }

  // Monkey-patch mem.write to ensure every write to 0x4000..0x5AFF is captured in mem._memWrites
  if (mem && typeof mem.write === 'function') {
    const originalWrite = mem.write.bind(mem);
    mem.write = function(addr, value) {
      const res = originalWrite(addr, value);
      try {
        if (addr >= 0x4000 && addr <= 0x5AFF) {
          mem._memWrites = mem._memWrites || [];
          mem._memWrites.push({ type: 'write', addr, value, t: (mem && mem.cpu) ? mem.cpu.tstates : (cpu ? cpu.tstates : 0), pc: (cpu && typeof cpu.getRegisters === 'function') ? cpu.PC : undefined });
        }
      } catch (e) { /* ignore */ }
      return res;
    };
    console.log('[TraceDiag] mem.write monkey-patched to force-log writes');
  }

  // We'll capture N frames
  const FRAMES = Number(process.env.FRAMES) || 200; // allow override from tests
  const TPF = 69888; // t-states per frame

  // Optional: inject a keypress during capture to exercise in-game logic
  // Configure via env: PRESS_FRAME (frame index) and PRESS_DURATION (frames)
  const PRESS_FRAME = Math.max(-1, parseInt(process.env.PRESS_FRAME || '-1', 10));
  const PRESS_DURATION = Math.max(1, parseInt(process.env.PRESS_DURATION || '2', 10));
  if (PRESS_FRAME >= 0) console.log('[TraceDiag] will press key "5" at frame', PRESS_FRAME, 'for', PRESS_DURATION, 'frames');

  const frames = [];

  // Take one warm-up frame to match the state captured by the
  // original jsspeccy reference trace.  That trace starts with the CPU
  // already having executed one full raster; without this the first frame
  // in our local captures would be offset by a full frame and every
  // subsequent comparison would require a manual index shift.
  cpu.runFor(TPF);

  for (let f = 0; f < FRAMES; f++) {
    // Prepare frame
    cpu.frameStartTstates = cpu.tstates;
    cpu._microTraceEnabled = true;
    cpu._microLog = [];
    mem._memWrites = [];
    // reset per-frame contention log so trace frames include only this-frame events
    mem._contentionLog = [];
    emu._portWrites = [];    

    // optionally press/release key around this frame
    try {
      if (PRESS_FRAME >= 0 && f === PRESS_FRAME) {
        try { if (emu && emu.input && typeof emu.input.pressKey === 'function') { emu.input.pressKey('5'); console.log('[TraceDiag] injected pressKey("5") at frame', f); } } catch (e) { }
      }
      if (PRESS_FRAME >= 0 && f === (PRESS_FRAME + PRESS_DURATION - 1)) {
        try { if (emu && emu.input && typeof emu.input.releaseKey === 'function') { emu.input.releaseKey('5'); console.log('[TraceDiag] injected releaseKey("5") at frame', f); } } catch (e) { }
      }
    } catch (e) { /* ignore */ }

    // Run one frame
    cpu.runFor(TPF);

    // DIAGNOSTICS: dump microLog, memory page1 contents and mem._memWrites for visibility
    try {
      console.log('[TraceDiag] cpu._microLog.length =', cpu._microLog ? cpu._microLog.length : 0);
      if (cpu._microLog && cpu._microLog.length > 0) console.log('[TraceDiag] cpu._microLog (head 40):', cpu._microLog.slice(0,40));
      console.log('[TraceDiag] mem.pages[1][0..8] =', mem.pages[1] ? Array.from(mem.pages[1].subarray(0,8)) : null);
      console.log('[TraceDiag] mem._memWrites (last 20) =', (mem._memWrites || []).slice(-20));
    } catch (e) { console.error('[TraceDiag] diagnostics failed', e); }

    // Gather data
    const regs = cpu.getRegisters ? cpu.getRegisters() : {
      A: cpu.A, F: cpu.F, B: cpu.B, C: cpu.C, D: cpu.D, E: cpu.E, H: cpu.H, L: cpu.L,
      PC: cpu.PC, SP: cpu.SP, I: cpu.I, R: cpu.R, IFF1: cpu.IFF1, IFF2: cpu.IFF2, IM: cpu.IM
    };

    let memWrites = mem._memWrites ? mem._memWrites.slice() : [];
    const portWrites = emu._portWrites ? emu._portWrites.slice() : [];

    // Limit micro-log size per frame to avoid producing excessively large
    // JSON payloads. Tests only need a sample — keep the head and indicate
    // if truncation occurred.
    const MAX_MICRO_PER_FRAME = parseInt(process.env.MAX_MICRO_PER_FRAME || '2000', 10) || 2000;
    let micro = [];
    if (cpu._microLog && Array.isArray(cpu._microLog)) {
      if (cpu._microLog.length > MAX_MICRO_PER_FRAME) {
        micro = cpu._microLog.slice(0, MAX_MICRO_PER_FRAME);
        micro._truncated = true; // marker for diagnostics
      } else {
        micro = cpu._microLog.slice();
      }
    }

    // NOTE: Synthetic memWrite append removed — memory writes should be
    // recorded deterministically by the emulator. If the second write is
    // missing we want tests to fail so the underlying timing issue is fixed.

    // Sound toggles (copy)
    const toggles = sound ? (sound._toggles ? sound._toggles.slice() : []) : [];

    // Include contention diagnostics so tests can compare against reference.
    // Cap to MAX_CONTENTION_PER_FRAME entries to prevent huge trace files.
    const MAX_CONTENTION_PER_FRAME = parseInt(process.env.MAX_CONTENTION_PER_FRAME || '50', 10) || 50;
    const contentionLog = (mem._contentionLog || []).slice(0, MAX_CONTENTION_PER_FRAME);
    const contentionHits = mem._contentionHits || 0;

    frames.push({ frame: f, startT: cpu.frameStartTstates, tstates: cpu.tstates, regs, memWrites, portWrites, micro, toggles, contentionLog, contentionHits });

    // Periodic flush to disk to limit memory
    if ((f + 1) % 20 === 0) {
      const partialFile = path.join(outDir, `jetpac_trace_partial_frame_${f}.json`);
      fs.writeFileSync(partialFile, JSON.stringify({ meta: { framesSoFar: f + 1 }, frames }));
      console.log(`Wrote partial trace up to frame ${f} -> ${partialFile}`);
    }
  }

  const outFile = path.join(outDir, 'jetpac_trace.json');
  fs.writeFileSync(outFile, JSON.stringify({ meta: { frames: FRAMES, tstatesPerFrame: TPF }, frames }));
  console.log('Wrote full trace to', outFile);
}

main().catch(e => { console.error('Trace capture failed:', e); process.exit(1); });

#!/usr/bin/env node
import fs from 'fs';
import path from 'path';

const TOL = 1; // tolerance in T-states when matching events

function loadTrace(p) {
  return JSON.parse(fs.readFileSync(p, 'utf8'));
}

function normalizeEvents(frame) {
  const evs = [];
  if (frame.memWrites) for (const m of frame.memWrites) evs.push({ type: 'memWrite', addr: m.addr, value: m.value, t: m.t });
  if (frame.portWrites) for (const p of frame.portWrites) evs.push({ type: 'portWrite', port: p.port, value: p.value, t: p.tstates || p.t });
  if (frame.regs && frame.regsSnapshot) {
    // unlikely here; kept for completeness
    evs.push({ type: 'regsSnapshot', regs: frame.regsSnapshot.regs, t: frame.regsSnapshot.t });
  }
  return evs.sort((a,b) => (a.t||0) - (b.t||0));
}

function findBestMatch(refEv, ourEvents, usedIdx) {
  let best = { idx: -1, dt: Infinity };
  for (let i = 0; i < ourEvents.length; i++) {
    if (usedIdx.has(i)) continue;
    const oe = ourEvents[i];
    if (oe.type !== refEv.type) continue;
    let keyMatch = true;
    if (refEv.type === 'memWrite') keyMatch = (refEv.addr === oe.addr && refEv.value === oe.value);
    if (refEv.type === 'portWrite') keyMatch = ((refEv.port & 0xFF) === (oe.port & 0xFF) && refEv.value === oe.value); // compare only low byte of port (ZX Spectrum ignores high byte)
    if (!keyMatch) continue;
    const dt = Math.abs((refEv.t || 0) - (oe.t || 0));
    if (dt < best.dt) best = { idx: i, dt };
  }
  return best;
}

function compareFrame(refFrame, ourFrame, frameIndex) {
  const refE = normalizeEvents(refFrame);
  const ourE = normalizeEvents(ourFrame);
  const used = new Set();
  const report = { frame: frameIndex, matches: [], missing: [], unexpected: [] };

  for (const r of refE) {
    const best = findBestMatch(r, ourE, used);
    if (best.idx === -1) {
      report.missing.push(r);
    } else {
      const oe = ourE[best.idx];
      used.add(best.idx);
      report.matches.push({ ref: r, our: oe, dt: best.dt, withinTolerance: best.dt <= TOL });
    }
  }

  for (let i = 0; i < ourE.length; i++) {
    if (!used.has(i)) report.unexpected.push(ourE[i]);
  }

  return report;
}

function short(ev) {
  if (!ev) return '';
  if (ev.type === 'memWrite') return `mem@0x${ev.addr.toString(16)}=0x${ev.value.toString(16)} @ t=${ev.t}`;
  if (ev.type === 'portWrite') return `port@0x${(ev.port||0).toString(16)}=0x${ev.value.toString(16)} @ t=${ev.t}`;
  return JSON.stringify(ev);
}

async function main() {
  const args = process.argv.slice(2);
  if (args.length < 3) {
    console.error('Usage: compare_frame_events.mjs <traceA.json> <traceB.json> <frameIndex>');
    process.exit(1);
  }
  const [aPath, bPath, frameIdxStr] = args;
  const frameIdx = Number(frameIdxStr || 0);
  const A = loadTrace(aPath);
  const B = loadTrace(bPath);
  if (!A.frames || !B.frames) { console.error('Invalid trace format'); process.exit(1); }
  if (frameIdx < 0 || frameIdx >= Math.min(A.frames.length, B.frames.length)) { console.error('Frame index out of range'); process.exit(1); }

  const rep = compareFrame(B.frames[frameIdx], A.frames[frameIdx], frameIdx); // ref=B, our=A

  console.log(`Frame ${frameIdx} comparison:`);
  console.log(`  Matches (${rep.matches.length}):`);
  for (const m of rep.matches) console.log(`    ref: ${short(m.ref)}  <=>  our: ${short(m.our)}  dt=${m.dt} ${m.withinTolerance? 'OK' : 'MIS'}`);
  console.log(`  Missing in our trace (${rep.missing.length}):`);
  for (const mm of rep.missing) console.log(`    missing ref: ${short(mm)}`);
  console.log(`  Unexpected in our trace (${rep.unexpected.length}):`);
  for (const u of rep.unexpected) console.log(`    unexpected our: ${short(u)}`);
}

main().catch(e => { console.error('compare_frame_events failed', e); process.exit(1); });

#!/usr/bin/env node
/*
  compare_jsspeccy_and_local.mjs

  - Launches a reference JSSpeccy instance (default: https://jsspeccy.zxdemo.org/)
  - Captures mem4800 + recent memWrites + PC/R timeline after pressing '5'
  - Runs the local zxspeccjs Emulator (same Jetpac .z80) in-Node, simulates pressing '5'
  - Compares the two traces and writes a JSON report to ./traces/compare_jsspeccy_vs_local.json

  Usage:
    node tests/scripts/compare_jsspeccy_and_local.mjs [--headed] [--url <JSSPECCY_URL>]

  Notes:
    - This is a diagnostic helper (not a unit test). Run locally when you need a direct
      parity comparison between the reference and our emulator.
*/

import fs from 'fs';
import path from 'path';
import { chromium } from 'playwright';
import { Loader } from '../../src/loader.mjs';
import { Emulator } from '../../src/main.mjs';
import { Z80 } from '../../src/z80.mjs';

const DEFAULT_REF = process.env.REFERENCE_URL || 'https://jsspeccy.zxdemo.org/';
const ARCHIVE_Z80_URL = 'https://cors.archive.org/cors/zx_Jetpac_1983_Ultimate_Play_The_Game_a_16K/Jetpac_1983_Ultimate_Play_The_Game_a_16K.z80';

const args = process.argv.slice(2);
const headed = args.includes('--headed');
const urlIdx = args.indexOf('--url');
const refUrl = urlIdx !== -1 && args[urlIdx + 1] ? args[urlIdx + 1] : DEFAULT_REF;

const outPath = path.resolve(process.cwd(), 'traces', 'compare_jsspeccy_vs_local.json');

async function captureJSSpeccy({ headed, url }) {
  const browser = await chromium.launch({ headless: !headed, args: ['--no-sandbox'] });
  const page = await browser.newPage({ timeout: 30000 });
  await page.goto(url, { waitUntil: 'load', timeout: 20000 }).catch(() => {});

  // Attempt to find Jetpac entry and send START (best-effort; tolerant of UI variants)
  try {
    // reuse logic similar to jsspeccy-jetpac-automation.mjs but compact
    await page.waitForTimeout(1200);
    // try search box
    const searchInput = page.locator('input[type=search], input[placeholder*=Search]').first();
    if (await searchInput.count()) {
      await searchInput.fill('Jetpac');
      await page.keyboard.press('Enter');
      await page.waitForTimeout(600);
    } else {
      // fallback: type into page
      await page.keyboard.type('Jetpac');
      await page.keyboard.press('Enter');
      await page.waitForTimeout(600);
    }

    // click result if present
    const exact = page.locator('text=Jetpac [a][16K]').first();
    if (await exact.count()) await exact.click({ force: true }).catch(() => {});
    await page.waitForTimeout(1200);

    // find canvas and press '5'
    const canvas = page.locator('canvas, #screen').first();
    await canvas.waitFor({ state: 'visible', timeout: 8000 }).catch(() => {});
    await canvas.click({ force: true }).catch(() => {});
    await canvas.press('5').catch(() => page.keyboard.press('5'));
    await page.waitForTimeout(600);
  } catch (e) {
    // non-fatal — we'll still try to extract diagnostics
  }

  // Read diagnostics from page
  const diag = await page.evaluate(() => {
    const maybe = window.emu || window.Speccy || window.jsSpeccy || window.JSSpeccy || window.SpeccyJS;
    const out = { found: !!maybe };
    try { out.pc = maybe && maybe.cpu ? maybe.cpu.PC : null; } catch (e) { out.pc = null; }
    try { out.mem4800 = maybe && maybe.memory && maybe.memory.pages ? Array.from(maybe.memory.pages[1].slice(0x4800 - 0x4000, 0x4800 - 0x4000 + 64)) : null; } catch (e) { out.mem4800 = null; }
    try { out.memWrites = (maybe && maybe.memory && Array.isArray(maybe.memory._memWrites)) ? maybe.memory._memWrites.slice(-256) : (window.__ZX_DEBUG__ && Array.isArray(window.__ZX_DEBUG__.memWrites) ? window.__ZX_DEBUG__.memWrites.slice(-256) : []); } catch (e) { out.memWrites = null; }
    try { out.portWrites = (maybe && Array.isArray(maybe._portWrites)) ? maybe._portWrites.slice(-256) : (window.__ZX_DEBUG__ && Array.isArray(window.__ZX_DEBUG__.portWrites) ? window.__ZX_DEBUG__.portWrites.slice(-256) : []); } catch (e) { out.portWrites = null; }
    try { out.soundToggles = (maybe && maybe.sound && Array.isArray(maybe.sound._toggles)) ? maybe.sound._toggles.slice(-128) : null; } catch (e) { out.soundToggles = null; }
    return out;
  }).catch(err => ({ error: String(err) }));

  await browser.close();
  return { url, headed, diag };
}

async function runLocalZX({ headless = true } = {}) {
  // Download Jetpac .z80 from Archive.org and parse
  const res = await fetch(ARCHIVE_Z80_URL);
  if (!res.ok) throw new Error('Failed to fetch Jetpac .z80 from archive.org');
  const buf = new Uint8Array(await res.arrayBuffer());
  const parsed = Loader.parseZ80(buf.buffer);
  if (!parsed || !parsed.snapshot || !parsed.snapshot.ram) throw new Error('Parsed snapshot missing RAM');

  // Create emulator with canvas stub
  const canvasStub = { width: 320, height: 240, style: {}, getContext: () => ({ createImageData: () => ({ data: new Uint8ClampedArray(320 * 240 * 4) }), putImageData: () => {}, fillRect: () => {}, imageSmoothingEnabled: false }), toDataURL: () => '' };
  const emu = new Emulator({ canvas: canvasStub, statusEl: {} });
  if (!emu.memory) await emu._createCore(parsed.rom || null);

  // Apply RAM + registers
  const ram = parsed.snapshot.ram;
  if (ram.length >= 0xC000) {
    emu.memory.pages[1].set(ram.subarray(0x0000, 0x4000));
    emu.memory.pages[2].set(ram.subarray(0x4000, 0x8000));
    emu.memory.pages[3].set(ram.subarray(0x8000, 0xC000));
  }
  emu._applySnapshot_registerRestore(parsed.snapshot.registers || {});

  // Ensure frameBuffer updated
  if (emu.ula && emu.ula.frameBuffer && typeof emu.ula.frameBuffer.generateFromMemory === 'function') emu.ula.frameBuffer.generateFromMemory();

  // Instrument memory writes collection
  emu.memory._memWrites = [];
  const origWrite = emu.memory.write.bind(emu.memory);
  emu.memory.write = function (addr, value) {
    const r = origWrite(addr, value);
    try { if (addr >= 0x4000 && addr <= 0x5AFF) emu.memory._memWrites.push({ addr, value, pc: emu.cpu ? emu.cpu.PC : null, t: emu.cpu ? emu.cpu.tstates : null }); } catch (e) { /* ignore */ }
    return r;
  };

  emu._portWrites = [];
  if (emu.ula && typeof emu.ula.writePort === 'function') {
    const origUlaOut = emu.ula.writePort.bind(emu.ula);
    emu.ula.writePort = function (port, value) {
      emu._portWrites.push({ port, value, pc: emu.cpu ? emu.cpu.PC : null, t: emu.cpu ? emu.cpu.tstates : null });
      return origUlaOut(port, value);
    };
  }

  // Simulate pressing '5'
  try { emu.input.pressKey('5'); } catch (e) { /* ignore */ }

  // Run a few frames (short window) and collect memWrites
  const FRAMES = 12;
  const tpf = emu.tstatesPerFrame || 69888;
  for (let f = 0; f < FRAMES; f++) {
    emu.cpu.runFor(tpf);
    // small pause for completeness
  }

  const pc = emu.cpu ? emu.cpu.PC : null;
  const mem4800 = emu.memory.pages[1] ? Array.from(emu.memory.pages[1].slice(0x4800 - 0x4000, 0x4800 - 0x4000 + 64)) : null;
  const memWrites = (emu.memory._memWrites || []).slice(-256);
  const portWrites = (emu._portWrites || []).slice(-256);

  return { pc, mem4800, memWrites, portWrites };
}

function diffArrays(a, b) {
  if (!a || !b) return { equal: false, reason: 'missing' };
  if (a.length !== b.length) return { equal: false, reason: 'length' };
  const diffs = [];
  for (let i = 0; i < a.length; i++) if (a[i] !== b[i]) diffs.push({ idx: i, ours: a[i], ref: b[i] });
  return { equal: diffs.length === 0, diffs };
}

