(async function(){
  const canvasStub = { width:320,height:240,style:{},getContext:()=>({ createImageData:()=>({ data:new Uint8ClampedArray(320*240*4) }), putImageData:()=>{}, fillRect:()=>{} }), toDataURL:()=>'' };
