      case 0xC3: return 'JP nn';
      case 0x00: return 'NOP';
      case 0xED: return 'ED prefix';
      case 0xDD: return 'DD prefix';
      case 0xFD: return 'FD prefix';
      case 0xCB: return 'CB prefix';
      default: return `DB 0x${opcode.toString(16).padStart(2, '0')}`;
