  const byte = spec48[i];
  const hex = byte.toString(16).padStart(2, '0');
  console.log(`  0x${i.toString(16).padStart(4, '0')}: 0x${hex} ${byte.toString(10).padStart(3)} ${byte >= 32 && byte < 127 ? `'${String.fromCharCode(byte)}'` : ' '}`);
}
console.log();

