  for (let addr = 0x4000; addr < 0x5800; addr++) {
    const value = memory.read(addr);
    displaySum += value;
    if (value !== 0) displayNonZero++;
  }
  
  // Check attribute file (0x5800-0x5AFF)
  let attrSum = 0;
  let attrNonZero = 0;
  for (let addr = 0x5800; addr < 0x5B00; addr++) {
    const value = memory.read(addr);
    attrSum += value;
    if (value !== 0) attrNonZero++;
  }
  
