function find(seq) {
  const offs = [];
  for (let i = 0; i <= buf.length - seq.length; i++) {
    let ok = true;
    for (let j = 0; j < seq.length; j++) {
      if (buf[i + j] !== seq[j]) { ok = false; break; }
    }
    if (ok) offs.push(i);
  }
  return offs;
}

