import { chromium } from '@playwright/test';

async function main(){
  const browser = await chromium.launch();
  const page = await browser.newPage();
  await page.goto('http://localhost:8080/');

  await page.evaluate(() => {
    if(!window.__PC_WATCHER__){
      window.__PC_WATCHER__ = { history: [], _interval: null };
      const poll = () => {
        try{
          const tryNames = ['__ZX_DEBUG__','__ZX_STATE__','emulator','spec','zx','z80','cpu'];
          let pc;
          if(window.__LAST_PC__ !== undefined) pc = window.__LAST_PC__;
          else {
            for(const n of tryNames){
              const obj = window[n];
              if(!obj) continue;
              if(typeof obj.getRegisters === 'function'){
                try{ const r = obj.getRegisters(); if(r && (r.pc !== undefined || r.PC !== undefined)){ pc = r.pc ?? r.PC; break; } }catch(e){ void e; }
              }
              if(obj.registers && (obj.registers.pc !== undefined || obj.registers.PC !== undefined)){
                pc = obj.registers.pc ?? obj.registers.PC; break;
              }
            }
          }
          if(typeof pc === 'number'){
            const h = window.__PC_WATCHER__.history;
            if(h.length === 0 || h[h.length-1] !== pc) h.push(pc);
            if(h.length > 2000) h.shift();
          }
        }catch(e){ void e; }
      };
      if(typeof requestAnimationFrame === 'function'){
        let rafId = null;
        const tick = () => { poll(); rafId = requestAnimationFrame(tick); };
        rafId = requestAnimationFrame(tick);
        window.__PC_WATCHER__._interval = { stop: () => cancelAnimationFrame(rafId) };
      } else {
        const id = setInterval(poll, 16);
        window.__PC_WATCHER__._interval = { stop: () => clearInterval(id) };
      }
    }
  });

  // click start
  try{ const start = await page.locator('button:has-text("Start")').first(); if(await start.isVisible()) await start.click(); }catch(e){ void e; }

  const addresses = [0x0000, 0x0001, 0x0002, 0x0005, 0x11CB];
  const timeout = 60000; const pollInterval = 50;
  const startTime = Date.now();
  const results = [];
  let nextIndex = 0;
  while(Date.now() - startTime < timeout){
    const state = await page.evaluate(() => {
      const tryNames = ['__ZX_DEBUG__','__ZX_STATE__','emulator','spec','zx','z80','cpu'];
      for(const n of tryNames){
        const obj = window[n];
        if(!obj) continue;
        if(typeof obj.getRegisters === 'function'){
          try{ return { regs: obj.getRegisters(), pc: obj.getRegisters().pc ?? obj.getRegisters().PC }; }catch(e){ void e; }
        }
        if(obj.registers) return { regs: obj.registers, pc: obj.registers.pc ?? obj.registers.PC };
      }
      if(window.__LAST_PC__ !== undefined) return { pc: window.__LAST_PC__ };
      if(window.__PC_WATCHER__ && Array.isArray(window.__PC_WATCHER__.history)){
        const last = window.__PC_WATCHER__.history[window.__PC_WATCHER__.history.length-1];
        return { pc: last };
      }
      return null;
    }).catch(() => null);

    console.log('polled state:', state && state.pc);
    if(state && typeof state.pc === 'number'){
      const pc = state.pc; const target = addresses[nextIndex];
      if(pc === target || pc === target + 1){
        results.push({ address: target, pc, regs: state.regs });
        nextIndex++;
        console.log('matched', target.toString(16));
        if(nextIndex >= addresses.length) break;
      }
    }
    await new Promise(r => setTimeout(r, pollInterval));
  }

  console.log('results:', results);
  await browser.close();
}

main().catch(e=>{ console.error(e); process.exit(1); });

import spec48 from '../src/roms/spec48.js';
import { Z80 } from '../src/z80.mjs';
import { Memory } from '../src/memory.mjs';
import { ULA } from '../src/ula.mjs';

const memory = new Memory({ romBuffer: spec48.bytes });
const cpu = new Z80(memory);
const canvas = { style: {}, getContext: () => ({ createImageData: ()=>({data:new Uint8ClampedArray(256*192*4)}), putImageData: ()=>{} }) };
const ula = new ULA(memory, canvas);
memory.attachCPU(cpu); ula.attachCPU(cpu);

// Stack watch instrumentation to capture any reads/writes to the top of RAM (stack)
const stackLog = [];
memory.enableStackWatch(0xFF00, 0xFFFF, (evt)=>{ stackLog.push(evt); if (stackLog.length>10000) stackLog.shift(); });

cpu.reset(); cpu.IFF1 = true; cpu.IFF2 = true; cpu._debugVerbose = true; // enable warnings for unimplemented opcodes to detect missing RETs or similar

// enable micro-tracing (push/pop/memory ops) for focused debugging
if (typeof cpu.enableMicroTrace === 'function') cpu.enableMicroTrace(); else { cpu._microTraceEnabled = true; cpu._microLog = cpu._microLog || []; }
// Attach IO bridge so ULA receives OUT/IN operations from CPU
cpu.io = { write: (port, value, t)=> { ula.writePort(port, value); }, read: (port)=> { return ula.readPort(port); } };
// Ensure ULA knows CPU interrupt state
ula.updateInterruptState();

let trace = [];
// pending BEFORE snapshots queue for hotspot instrumentation
const pendingBefore = [];
const ioLog = [];

cpu.debugCallback = (opcode, pc) => {
  // If there is a pending BEFORE snapshot, finalize it now using current CPU state (this is AFTER previous instruction)
  if (pendingBefore.length > 0) {
    const before = pendingBefore.shift();
    const afterRegs = { A: cpu.A, F: cpu.F, B: cpu.B, C: cpu.C, D: cpu.D, E: cpu.E, H: cpu.H, L: cpu.L, PC: cpu.PC, SP: cpu.SP, I: cpu.I, R: cpu.R, IM: cpu.IM, IFF1: cpu.IFF1, IFF2: cpu.IFF2, tstates: cpu.tstates };
    const dumpAddr = before.dumpAddr;
    const memBytesAfter = [];
    for (let i = 0; i < 16; i++) memBytesAfter.push(memory.read((dumpAddr + i) & 0xFFFF).toString(16).padStart(2, '0'));
    // collect IO activity between before and after tstates
    const ioBetween = ioLog.filter(w => w.t >= before.tstates && w.t <= cpu.tstates);
    console.log(`HOT AFTER: id=${before.id} pc=0x${before.pc.toString(16).padStart(4,'0')} op=0x${before.op.toString(16).padStart(2,'0')} t_before=${before.tstates} t_after=${cpu.tstates}`);
    console.log(`  before.regs=${JSON.stringify(before.regs)}
  after.regs=${JSON.stringify(afterRegs)}`);
    console.log(`  MEM AFTER @0x${dumpAddr.toString(16).padStart(4,'0')}: ${memBytesAfter.join(' ')}`);
    if (ioBetween.length) console.log(`  IO between: ${JSON.stringify(ioBetween)}`);
    const microBetween = (cpu._microLog || []).filter(m => m.t >= before.tstates && m.t <= cpu.tstates);
    if (microBetween.length) console.log(`  MICRO between: ${JSON.stringify(microBetween)}`);
    const stackBetween = (stackLog || []).filter(s => s.t >= before.tstates && s.t <= cpu.tstates);
    if (stackBetween.length) console.log(`  STACK between: ${JSON.stringify(stackBetween)}`);
  }

  trace.push({pc, opcode});
  if (trace.length > 1000) trace.shift();

  // Narrow instrumentation for suspected boot-loop hotspots
  const inHot1 = pc >= 0x0038 && pc <= 0x004A;
  const inHot2 = pc >= 0x028E && pc <= 0x0291;
  const inHot3 = pc === 0x02BF;
  if (inHot1 || inHot2 || inHot3) {
    const regs = { A: cpu.A, F: cpu.F, B: cpu.B, C: cpu.C, D: cpu.D, E: cpu.E, H: cpu.H, L: cpu.L, PC: pc, SP: cpu.SP, I: cpu.I, R: cpu.R, IM: cpu.IM, IFF1: cpu.IFF1, IFF2: cpu.IFF2, tstates: cpu.tstates };
    const dumpAddr = inHot2 ? 0x0288 : (inHot1 ? 0x0038 : 0x02B8);
    const memBytes = [];
    for (let i=0;i<16;i++) memBytes.push(memory.read((dumpAddr+i)&0xFFFF).toString(16).padStart(2,'0'));

    // create a BEFORE snapshot and push to queue; it will be finalized on the *next* debug callback (the AFTER state)
    const id = Math.floor(Math.random()*0xFFFF).toString(16).padStart(4,'0');
    pendingBefore.push({ id, pc, op: opcode, regs, dumpAddr, tstates: cpu.tstates });

    console.log(`HOT BEFORE: id=${id} pc=0x${pc.toString(16).padStart(4,'0')} OPC=0x${opcode.toString(16).padStart(2,'0')} t=${cpu.tstates} regs=${JSON.stringify(regs)}`);
    console.log(`MEM @0x${dumpAddr.toString(16).padStart(4,'0')}: ${memBytes.join(' ')}`);
  }
};

// Wrap CPU IO to capture port writes/reads for instrumentation
cpu.io = {
  write: (port, value, t)=> {
    ula.writePort(port, value);
    ioLog.push({dir: 'write', port: port & 0xFFFF, value: value & 0xFF, t: t, pc: cpu.PC});
  },
  read: (port)=> {
    const val = ula.readPort(port);
    ioLog.push({dir: 'read', port: port & 0xFFFF, value: val & 0xFF, t: cpu.tstates, pc: cpu.PC});
    return val;
  }
};

for (let frame=1; frame<=5; frame++){
  cpu.runFor(69888);
  const t = cpu.tstates;
  ula.generateInterrupt(69888);
  // show last 50 opcode executions
  console.log(`\n--- Frame ${frame} PC=${cpu.PC.toString(16).padStart(4,'0')} tstates=${t} traceLen=${trace.length}`);
  const last = trace.slice(-50);
  for (const e of last) console.log(`0x${e.opcode.toString(16).padStart(2,'0')} @ 0x${e.pc.toString(16).padStart(4,'0')}`);
}

// summarize frequent patterns
