for(const e of trace){ const key=`0x${e.opcode.toString(16).padStart(2,'0')}@0x${e.pc.toString(16).padStart(4,'0')}`; freq[key]=(freq[key]||0)+1; }
const entries = Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,20);
console.log('\nTop PC/opcode frequencies:');
